package workspace

import (
	"fmt"
	"os"
	"path/filepath"

	"gopkg.in/yaml.v3"
)

// AgentProfile configures model and effort level for a teammate.
type AgentProfile struct {
	Model  string `yaml:"model,omitempty"`
	Effort string `yaml:"effort,omitempty"`
}

// Config represents the workspace.yaml configuration.
type Config struct {
	RepoURL       string                  `yaml:"repo_url"`
	ProjectPath   string                  `yaml:"project_path"`
	DefaultBranch string                  `yaml:"default_branch"`
	ExtraROMounts []string                `yaml:"extra_ro_mounts"`
	ExtraRWMounts []string                `yaml:"extra_rw_mounts"`
	AgentEnv      map[string]string       `yaml:"agent_env"`
	AgentProfiles map[string]AgentProfile `yaml:"agent_profiles"`
}

// DirName is the name of the project-local workspace directory.
const DirName = ".agentsea"

// Workspace represents a loaded workspace with its config and directory.
type Workspace struct {
	Config Config
	Dir    string // absolute path to the .agentsea directory in the project root
}

// Load reads workspace.yaml from the given directory and returns a Workspace.
func Load(dir string) (*Workspace, error) {
	absDir, err := filepath.Abs(dir)
	if err != nil {
		return nil, fmt.Errorf("resolving workspace dir: %w", err)
	}

	data, err := os.ReadFile(filepath.Join(absDir, "workspace.yaml"))
	if err != nil {
		return nil, fmt.Errorf("reading workspace.yaml: %w", err)
	}

	var cfg Config
	if err := yaml.Unmarshal(data, &cfg); err != nil {
		return nil, fmt.Errorf("parsing workspace.yaml: %w", err)
	}

	return &Workspace{Config: cfg, Dir: absDir}, nil
}

// Detect finds the workspace by walking up from cwd looking for .agentsea/workspace.yaml.
func Detect() (*Workspace, error) {
	cwd, err := os.Getwd()
	if err != nil {
		return nil, fmt.Errorf("getting cwd: %w", err)
	}
	return DetectFrom(cwd)
}

// DetectFrom walks up from the given directory looking for .agentsea/workspace.yaml.
func DetectFrom(startDir string) (*Workspace, error) {
	dir, err := filepath.Abs(startDir)
	if err != nil {
		return nil, fmt.Errorf("resolving start dir: %w", err)
	}

	for {
		wsDir := filepath.Join(dir, DirName)
		wsFile := filepath.Join(wsDir, "workspace.yaml")
		if _, err := os.Stat(wsFile); err == nil {
			return Load(wsDir)
		}

		parent := filepath.Dir(dir)
		if parent == dir {
			break // reached filesystem root
		}
		dir = parent
	}

	return nil, fmt.Errorf("no workspace found (no %s/workspace.yaml in any parent of %s)", DirName, startDir)
}

// AgentRepoPath returns the path to an agent's git repository clone.
func (w *Workspace) AgentRepoPath(name string) string {
	return filepath.Join(w.Dir, "agents", name, "repo")
}

// AgentSSHPath returns the path to an agent's SSH key directory.
func (w *Workspace) AgentSSHPath(name string) string {
	return filepath.Join(w.Dir, "agents", name, "ssh")
}

// CanonicalPath returns the path to the bare canonical clone.
func (w *Workspace) CanonicalPath() string {
	return filepath.Join(w.Dir, "canonical")
}

