		t.Errorf("error should mention bwrap, got: %v", err)
	}
}

func TestClaudePreflight_Success(t *testing.T) {
	t.Setenv("CLAUDE_CODE_TEAMMATE_COMMAND", "")
	setupWorkspace(t)
	setPathWithBinaries(t)

	cfg, err := claudePreflight([]string{"--resume", "--verbose"})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if cfg.ClaudeBin == "" {
		t.Error("ClaudeBin should not be empty")
	}
	if cfg.SeaBin == "" {
		t.Error("SeaBin should not be empty")
	}
	if len(cfg.Args) != 2 || cfg.Args[0] != "--resume" || cfg.Args[1] != "--verbose" {
		t.Errorf("Args = %v, want [--resume --verbose]", cfg.Args)
	}
}

func TestClaudePreflight_StripsDashDash(t *testing.T) {
	t.Setenv("CLAUDE_CODE_TEAMMATE_COMMAND", "")
	setupWorkspace(t)
	setPathWithBinaries(t)

	cfg, err := claudePreflight([]string{"--", "--resume"})
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(cfg.Args) != 1 || cfg.Args[0] != "--resume" {
		t.Errorf("Args = %v, want [--resume]", cfg.Args)
	}
}

func TestClaudePreflight_NoArgs(t *testing.T) {
	t.Setenv("CLAUDE_CODE_TEAMMATE_COMMAND", "")
	setupWorkspace(t)
	setPathWithBinaries(t)

	cfg, err := claudePreflight(nil)
	if err != nil {
		t.Fatalf("unexpected error: %v", err)
	}
	if len(cfg.Args) != 0 {
		t.Errorf("Args = %v, want empty", cfg.Args)
	}
}

func TestClaudePreflight_UnsetEnvVar(t *testing.T) {
	os.Unsetenv("CLAUDE_CODE_TEAMMATE_COMMAND")
	setupWorkspace(t)
	setPathWithBinaries(t)

	_, err := claudePreflight(nil)
	if err != nil {
		t.Fatalf("unexpected error with unset env var: %v", err)
	}
}

